import os
import zipfile
from flask import Flask, request, send_file, jsonify

app = Flask(__name__)

@app.route('/create_zip', methods=['POST'])
def create_zip():
    data = request.json
    file_path = data.get('file_path')

    if not file_path or not isinstance(file_path, str):
        return jsonify({"error": "Invalid input. Please provide a valid file path."}), 400

    if not os.path.exists(file_path):
        return jsonify({"error": "File path does not exist."}), 404

    zip_file_path = 'output.zip'
    with zipfile.ZipFile(zip_file_path, 'w') as zipf:
        for root, dirs, files in os.walk(file_path):
            for file in files:
                file_full_path = os.path.join(root, file)
                zipf.write(file_full_path, os.path.relpath(file_full_path, os.path.dirname(file_path)))

    return send_file(zip_file_path, as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)
